#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int kthLargestElement(int* nums, int numsSize, int k) {
    qsort(nums, numsSize, sizeof(int), compare);
    return nums[numsSize - k];
}

int main() {
    int nums[] = {1, 2, 3, 4, 5};
    int k = 2;
    int numsSize = sizeof(nums) / sizeof(nums[0]);
    printf("The Kth largest element in the array is: %d\n", kthLargestElement(nums, numsSize, k));
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int kthLargestElement(vector<int>& nums, int k) {
        sort(nums.begin(), nums.end());
        return nums[nums.size() - k];
    }
};

int main() {
    vector<int> nums = {1, 2, 3, 4, 5};
    int k = 2;
    Solution sol;
    cout << "The Kth largest element in the array is: " << sol.kthLargestElement(nums, k) << endl;
    return 0;
}

code.Java:
import java.util.Arrays;

class Solution {
    public int kthLargestElement(int[] nums, int k) {
        Arrays.sort(nums);
        return nums[nums.length - k];
    }
}

class Main {
    public static void main(String[] args) {
        int[] nums = {1, 2, 3, 4, 5};
        int k = 2;
        Solution sol = new Solution();
        System.out.println("The Kth largest element in the array is: " + sol.kthLargestElement(nums, k));
    }
}

